import {useEffect,useState,useRef} from "react";
import axios from "axios";
import {MapContainer,TileLayer,Popup,Circle,useMap} from "react-leaflet";
import "leaflet/dist/leaflet.css";

function ChangeMapView({coords}){
  const map = useMap();

  useEffect(()=>{
    if(coords){
      map.setView(coords,15);
    }
  },[coords,map]);

  return null;
}

export default function Admin(){

  const [alerts,setAlerts]=useState([]);
  const [loading,setLoading]=useState(true);
  const [error,setError]=useState("");
  const [selectedLocation,setSelectedLocation]=useState(null);
  const [playSound, setPlaySound] = useState(false);
  const lastAlertRef = useRef(null);

  const [pulse,setPulse]=useState(80);

  const loadAlerts = () => {
  axios.get("http://127.0.0.1:8000/api/admin-alerts/")
    .then(res => {

      if (res.data.length > 0) {
        const latestId = res.data[0].id;

        if (
          lastAlertRef.current !== null &&
          latestId !== lastAlertRef.current
        ) {
          alert("🚨 New Emergency Alert!");
          setPlaySound(true);
        }

        lastAlertRef.current = latestId;
      }

      setAlerts(res.data);
      setLoading(false);
    })
    .catch(() => {
      setError("Failed to load alerts");
      setLoading(false);
    });
};
  const getCurrentLocation = () => {
  return new Promise((resolve, reject) => {
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        resolve({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude
        });
      },
      (err) => reject(err)
    );
  });
};

  /* FIRST LOAD */
  useEffect(()=>{ 
    loadAlerts(); 
  },[]);

  /* AUTO REFRESH EVERY 1 MINUTE */
  useEffect(()=>{
    const interval=setInterval(()=>{
      loadAlerts();
    },10000);   // 10000 ms = 10 sec

    return ()=>clearInterval(interval);
  },[]);

  /* BLINKING MAP EFFECT */
  useEffect(()=>{
    const interval=setInterval(()=>{
      setPulse(prev => prev===80 ? 140 : 80);
    },700);

    return ()=>clearInterval(interval);
  },[]);
  useEffect(() => {
  const unlock = () => {
    const audio = document.getElementById("alertSound");
    if (audio) {
      audio.muted = true;
      audio.play()
        .then(() => {
          audio.pause();
          audio.currentTime = 0;
          audio.muted = false;
        })
        .catch(() => {});
    }
  };

  document.addEventListener("click", unlock, { once: true });

  return () => document.removeEventListener("click", unlock);
}, []);

useEffect(() => {
  if (playSound) {
    const audio = document.getElementById("alertSound");

    if (audio) {
      audio.currentTime = 0;

      audio.play().catch(() => {
        audio.muted = true;
        audio.play().then(() => {
          audio.muted = false;
        });
      });
    }

    setPlaySound(false);
  }
}, [playSound]);

  const resolveAlert = async (alert) => {
  try {

    const input = document.createElement("input");
    input.type = "file";
    input.accept = "image/*";
    input.capture = "environment";

    input.onchange = async (e) => {

      const file = e.target.files[0];
      if (!file) {
        alert("Photo is required!");
        return;
      }

      const location = await getCurrentLocation();

      const formData = new FormData();
      formData.append("photo", file);
      formData.append("lat", location.lat);
      formData.append("lng", location.lng);
      formData.append("alert_lat", alert.latitude);
      formData.append("alert_lng", alert.longitude);

      await axios.post(
        `http://127.0.0.1:8000/api/resolve-api/${alert.id}/`,
        formData
      );

      loadAlerts();
    };

    input.click();

  } catch (err) {
    console.log("Resolve error:", err);
    alert("Error resolving alert");
  }
};

  /* ALERT FILTERS */
  const active=alerts.filter(a=>a.status!=="resolved");
  const resolved=alerts.filter(a=>a.status==="resolved");

  /* EXPORT CSV */
  const exportCSV=()=>{
    const rows=[
      ["Device","Latitude","Longitude","Message","Status","Time"],
      ...alerts.map(a=>[
        a.device_id,
        a.latitude,
        a.longitude,
        a.message,
        a.status,
        new Date(a.timestamp).toLocaleString()
      ])
    ]

    const csvContent=
      "data:text/csv;charset=utf-8," +
      rows.map(e=>e.join(",")).join("\n")

    const encodedUri=encodeURI(csvContent);
    const link=document.createElement("a");

    link.setAttribute("href",encodedUri);
    link.setAttribute("download","alerts_report.csv");

    document.body.appendChild(link);
    link.click();
  }

  if(loading) return <div style={page}>Loading alerts...</div>;
  if(error) return <div style={page}>{error}</div>;

  return(
    <div style={page}>
      <audio id="alertSound" preload="auto">
  <source src="/alert.mp3" type="audio/mpeg" />
</audio>

      {/* HEADER */}
      <h1 style={{color:"#f97316"}}>
        ⚙️ Admin Control Center
      </h1>

      {/* STATS CARDS */}
      <div style={statsContainer}>

        <div style={card}>
          <h3>Total Alerts</h3>
          <p style={number}>{alerts.length}</p>
        </div>

        <div style={card}>
          <h3>Active Alerts</h3>
          <p style={{...number,color:"#ef4444"}}>{active.length}</p>
        </div>

        <div style={card}>
          <h3>Resolved Alerts</h3>
          <p style={{...number,color:"#22c55e"}}>{resolved.length}</p>
        </div>

        <button style={exportBtn} onClick={exportCSV}>
          Export Report
        </button>

      </div>

      {/* MAP */}
      <MapContainer
        center={[17.38,78.48]}
        zoom={11}
        style={{height:350,marginTop:20,borderRadius:12,overflow:"hidden"}}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

        <ChangeMapView coords={selectedLocation}/>

        {active.map(a=>(
          a.latitude && a.longitude && (
            <Circle
              key={a.id}
              center={[a.latitude,a.longitude]}
              radius={pulse}
              pathOptions={{
                color:"red",
                fillColor:"red",
                fillOpacity:0.5
              }}
            >
              <Popup>
                <strong>{a.message}</strong><br/>
                Status: {a.status}
              </Popup>
            </Circle>
          )
        ))}

        {selectedLocation && (
          <Circle
            center={selectedLocation}
            radius={pulse}
            pathOptions={{
              color:"#f97316",
              fillColor:"#f97316",
              fillOpacity:0.5
            }}
          >
            <Popup>Selected Alert Location</Popup>
          </Circle>
        )}

      </MapContainer>

      <h2 style={{marginTop:30}}>Active Alerts</h2>
      <Table alerts={active} resolveAlert={resolveAlert} setSelectedLocation={setSelectedLocation}/>

      <h2 style={{marginTop:30}}>Resolved Alerts History</h2>
      <Table alerts={resolved} setSelectedLocation={setSelectedLocation}/>

    </div>
  )
}

/* TABLE COMPONENT */

function Table({alerts,resolveAlert,setSelectedLocation}){

  const navigateToLocation=(lat,lon)=>{
    const url=`https://www.google.com/maps/dir/?api=1&destination=${lat},${lon}`;
    window.open(url,"_blank");
  }

  if(!alerts.length){
    return <p style={{marginTop:10,color:"white"}}>No alerts found</p>
  }

  return(
    <table style={table}>
      <thead>
        <tr>
          <th style={th}>Device</th>
          <th style={th}>Location</th>
          <th style={th}>Message</th>
          <th style={th}>Status</th>
          <th style={th}>Time</th>
          {resolveAlert && <th style={th}>Action</th>}
        </tr>
      </thead>

      <tbody>
      {alerts.map(a=>(
        <tr key={a.id} style={a.status!=="resolved"?blinkingRow:{}}>

          <td style={td}>{a.device_id}</td>

          <td style={td}>
            {a.latitude},{a.longitude}<br/>

            <button
              style={navigateBtn}
              onClick={()=>navigateToLocation(a.latitude,a.longitude)}
            >
              Navigate
            </button>

            <button
              style={viewBtn}
              onClick={()=>setSelectedLocation([a.latitude,a.longitude])}
            >
              View
            </button>
          </td>

          <td style={td}>{a.message}</td>

          <td style={td}>
            <span style={{
              padding:"4px 8px",
              borderRadius:6,
              background:a.status==="resolved"?"#16a34a":"#dc2626",
              color:"white",
              fontSize:12
            }}>
              {a.status}
            </span>
          </td>

          <td style={td}>
  {new Date(a.timestamp).toLocaleString()}

  {a.proof_image && (
    <div>
      <button
        style={{...btn, marginTop:5, background:"#22c55e"}}
        onClick={() => window.open(`http://127.0.0.1:8000${a.proof_image}`)}
      >
        View Proof
      </button>
    </div>
  )}
</td>
          {resolveAlert &&
            <td style={td}>
              <button
                style={btn}
                onClick={()=>resolveAlert(a)}>

                Resolve
              </button>
            </td>}
        </tr>
      ))}
      </tbody>
    </table>
  )
}

